mapper.select:
select a.application_id, a.topic_id, t.title as topic_title, t.teacher_id, a.student_id, u.nick_name as student_name, a.personal_note, a.status, a.reject_reason, a.reject_by, a.reject_time, a.del_flag, a.create_time from project_application a inner join project_topic t on t.topic_id = a.topic_id inner join sys_user u on u.user_id = a.student_id where t.teacher_id = #{teacherId} and a.status = 'Pending' and a.del_flag = '0'
and t.topic_id = #{topicId}
and (lower(t.title) like concat('%', lower(#{keyword}), '%') or lower(u.nick_name) like concat('%', lower(#{keyword}), '%') or lower(a.personal_note) like concat('%', lower(#{keyword}), '%'))
limit #{limit} offset #{offset}

select count(1) from project_application a inner join project_topic t on t.topic_id = a.topic_id inner join sys_user u on u.user_id = a.student_id where t.teacher_id = #{teacherId} and a.status = 'Pending' and a.del_flag = '0'
and t.topic_id = #{topicId}
and (lower(t.title) like concat('%', lower(#{keyword}), '%') or lower(u.nick_name) like concat('%', lower(#{keyword}), '%') or lower(a.personal_note) like concat('%', lower(#{keyword}), '%'))

select a.application_id, a.topic_id, t.title as topic_title, t.teacher_id, a.student_id, u.nick_name as student_name, a.personal_note, a.status, a.reject_reason, a.reject_by, a.reject_time, a.del_flag, a.create_time from project_application a inner join project_topic t on t.topic_id = a.topic_id inner join sys_user u on u.user_id = a.student_id where t.teacher_id = #{teacherId} and a.status in ('Approved', 'Rejected', 'Withdrawn') and a.del_flag = '0'
